import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';

const Sports = () => {
  const [events, setEvents] = useState([]);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [betAmount, setBetAmount] = useState(10);
  const [selection, setSelection] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const { fetchBalance } = useAuth();

  useEffect(() => {
    loadEvents();
  }, []);

  const loadEvents = async () => {
    try {
      const res = await api.get('/api/sports/events');
      setEvents(res.data);
    } catch (err) {
      console.error('Erro ao carregar eventos');
    }
  };

  const placeBet = async () => {
    if (!selectedEvent || !selection || betAmount <= 0) return;
    setLoading(true);
    setResult(null);
    try {
      const res = await api.post('/api/sports/bet', {
        eventId: selectedEvent.id,
        betAmount: parseFloat(betAmount),
        selection,
      });
      setTimeout(() => {
        setResult(res.data);
        fetchBalance();
        setLoading(false);
      }, 2000);
    } catch (err) {
      setResult({ message: err.response?.data?.message || 'Erro ao apostar' });
      setLoading(false);
    }
  };

  const sportIcons = { Futebol: '⚽', Basquete: '🏀', 'Tênis': '🎾' };

  const formatDate = (dateStr) => {
    const d = new Date(dateStr);
    return d.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
  };

  const styles = {
    container: { maxWidth: '1200px', margin: '0 auto', padding: '20px' },
    title: { fontFamily: "'Orbitron', sans-serif", fontSize: '32px', fontWeight: 700, marginBottom: '8px', textAlign: 'center' },
    subtitle: { textAlign: 'center', color: '#b0b0b0', marginBottom: '32px', fontSize: '15px' },
    eventsGrid: { display: 'flex', flexDirection: 'column', gap: '16px', marginBottom: '32px' },
    eventCard: (isSelected) => ({
      background: isSelected ? 'linear-gradient(135deg, rgba(220,0,0,0.15), #1a1a1a)' : '#1a1a1a',
      border: isSelected ? '2px solid #DC0000' : '1px solid #2a2a2a',
      borderRadius: '16px', padding: '24px', cursor: 'pointer',
      transition: 'all 0.3s ease',
    }),
    eventHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px', flexWrap: 'wrap', gap: '8px' },
    eventSport: { display: 'flex', alignItems: 'center', gap: '8px' },
    sportBadge: { background: '#DC0000', color: '#fff', padding: '4px 12px', borderRadius: '20px', fontSize: '12px', fontWeight: 600 },
    eventDate: { color: '#b0b0b0', fontSize: '13px' },
    eventTeams: {
      display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '20px',
      fontSize: '20px', fontWeight: 700, marginBottom: '16px',
    },
    vs: { color: '#DC0000', fontFamily: "'Orbitron', sans-serif", fontSize: '14px' },
    oddsRow: { display: 'flex', gap: '12px', justifyContent: 'center', flexWrap: 'wrap' },
    oddBtn: (active) => ({
      padding: '12px 24px', borderRadius: '10px', border: 'none', cursor: 'pointer',
      background: active ? 'linear-gradient(135deg, #FFD700, #B8860B)' : '#2a2a2a',
      color: active ? '#000' : '#fff', fontWeight: 600, fontSize: '14px',
      transition: 'all 0.3s ease', minWidth: '120px', textAlign: 'center',
    }),
    oddLabel: { fontSize: '11px', color: active => active ? '#333' : '#b0b0b0', display: 'block', marginBottom: '4px' },
    oddValue: { fontSize: '18px', fontWeight: 800 },
    betSection: {
      background: '#1a1a1a', border: '1px solid #2a2a2a', borderRadius: '16px',
      padding: '32px', marginTop: '24px',
    },
    betTitle: { fontFamily: "'Orbitron', sans-serif", fontSize: '20px', fontWeight: 600, marginBottom: '20px', color: '#FFD700' },
    betRow: { display: 'flex', gap: '12px', alignItems: 'center', marginBottom: '20px', flexWrap: 'wrap' },
    resultBox: (won) => ({
      marginTop: '20px', padding: '24px', borderRadius: '12px',
      background: won ? 'rgba(0,200,83,0.1)' : 'rgba(255,23,68,0.1)',
      border: `1px solid ${won ? 'rgba(0,200,83,0.3)' : 'rgba(255,23,68,0.3)'}`,
      textAlign: 'center', animation: 'slideUp 0.5s ease',
    }),
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>⚽ <span className="gold-text">Apostas Esportivas</span></h1>
      <p style={styles.subtitle}>Escolha um evento e faça sua aposta!</p>

      <div style={styles.eventsGrid}>
        {events.map(event => (
          <div key={event.id} style={styles.eventCard(selectedEvent?.id === event.id)}
            onClick={() => { setSelectedEvent(event); setResult(null); setSelection(''); }}>
            <div style={styles.eventHeader}>
              <div style={styles.eventSport}>
                <span style={{ fontSize: '24px' }}>{sportIcons[event.sport]}</span>
                <span style={styles.sportBadge}>{event.sport}</span>
                <span className="badge-live">AO VIVO</span>
              </div>
              <span style={styles.eventDate}>{formatDate(event.date)}</span>
            </div>
            <div style={styles.eventTeams}>
              <span>{event.team1 || event.player1}</span>
              <span style={styles.vs}>VS</span>
              <span>{event.team2 || event.player2}</span>
            </div>
            <div style={styles.oddsRow}>
              {Object.entries(event.odds).map(([key, value]) => {
                const label = key === 'team1Win' ? (event.team1 || event.player1) :
                  key === 'team2Win' ? (event.team2 || event.player2) :
                    key === 'draw' ? 'Empate' :
                      key === 'player1Win' ? event.player1 : event.player2;
                return (
                  <button key={key} style={styles.oddBtn(selection === key)}
                    onClick={(e) => { e.stopPropagation(); setSelectedEvent(event); setSelection(key); }}>
                    <span style={{ fontSize: '11px', color: selection === key ? '#333' : '#b0b0b0', display: 'block', marginBottom: '4px' }}>{label}</span>
                    <span style={{ fontSize: '18px', fontWeight: 800 }}>{value.toFixed(2)}</span>
                  </button>
                );
              })}
            </div>
          </div>
        ))}
      </div>

      {selectedEvent && selection && (
        <div style={styles.betSection}>
          <h3 style={styles.betTitle}>🎯 Confirmar Aposta</h3>
          <p style={{ color: '#b0b0b0', marginBottom: '16px' }}>
            {selectedEvent.team1 || selectedEvent.player1} vs {selectedEvent.team2 || selectedEvent.player2} —
            Odd: <strong style={{ color: '#FFD700' }}>{selectedEvent.odds[selection]?.toFixed(2)}</strong>
          </p>

          <div style={styles.betRow}>
            <span style={{ color: '#b0b0b0' }}>Valor: R$</span>
            <input className="input-field" type="number" min="1" value={betAmount}
              onChange={(e) => setBetAmount(e.target.value)} style={{ width: '120px' }} />
            {[10, 25, 50, 100, 200].map(v => (
              <button key={v} onClick={() => setBetAmount(v)}
                style={{ padding: '8px 14px', borderRadius: '8px', border: 'none', cursor: 'pointer', background: betAmount === v ? '#FFD700' : '#2a2a2a', color: betAmount === v ? '#000' : '#fff', fontWeight: 600, fontSize: '13px' }}>
                R${v}
              </button>
            ))}
          </div>

          <p style={{ color: '#b0b0b0', marginBottom: '20px' }}>
            Possível retorno: <strong style={{ color: '#00c853' }}>R$ {(betAmount * selectedEvent.odds[selection]).toFixed(2)}</strong>
          </p>

          <button className="btn-gold" onClick={placeBet} disabled={loading} style={{ padding: '14px 40px', fontSize: '16px' }}>
            {loading ? 'APOSTANDO...' : '💰 CONFIRMAR APOSTA'}
          </button>

          {result && !loading && (
            <div style={styles.resultBox(result.winAmount > 0)}>
              <p style={{ fontSize: '18px', fontWeight: 700, color: result.winAmount > 0 ? '#00c853' : '#ff1744', marginBottom: '8px' }}>
                {result.message}
              </p>
              {result.winAmount > 0 && (
                <p style={{ color: '#b0b0b0' }}>Ganho: <strong style={{ color: '#00c853' }}>R$ {result.winAmount?.toFixed(2)}</strong></p>
              )}
              <p style={{ color: '#b0b0b0', marginTop: '8px' }}>Novo saldo: R$ {result.newBalance?.toFixed(2)}</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default Sports;
